sql:
SELECT AVG(btc_to_usdt) AS average_price
FROM btc_price_history
WHERE changes_percentage > 1.0;

SELECT day, AVG(changes_percentage) AS average_price_change
FROM btc_price_history
GROUP BY day;

SELECT date, btc_to_usdt
FROM btc_price_history
ORDER BY date DESC;

SELECT 
    EXISTS (
        SELECT 1 
        FROM alerts 
        WHERE condition = 'price'
    ) AS alert_exists;

SELECT id
FROM btc_price_history
WHERE changes_percentage > 1;

SELECT high_price
FROM btc_price_history
WHERE date = '2023-06-07';
